external_knowledge:
- 'Prominently produce oil and gas' refers to wells specifically categorized as 'Oil and gas';
- 'Top-performing wells' are defined as having the highest oil production ranked within their respective states;
- The query limits the results to the three highest-ranking wells per state.

sql:
SELECT w.name AS well_name, o.operator_name AS operator_name
FROM wells w
INNER JOIN operators o ON w.operator = o.operator_id;

SELECT name
FROM wells
WHERE depth = (SELECT MAX(depth) FROM wells);

SELECT state_id, COUNT(api) AS number_of_wells
FROM wells
GROUP BY state_id;

SELECT SUM(p.oil_volume + p.gas_volume) AS total_production_volume
FROM production p
WHERE p.api = '0' AND p.date BETWEEN '1980-01-01' AND '2020-12-31';

SELECT w.name AS WellName, w.last_inspection_date AS MostRecentInspection
FROM wells w
WHERE w.status = 'Active' AND w.last_inspection_date > '2023-01-01';

SELECT COUNT(api) AS active_well_count
FROM wells
WHERE status = 'Active';

SELECT api, name, status, depth, COUNT(api) AS well_count
FROM wells
GROUP BY api, name, status, depth;
